// ==UserScript==
// @name         PelotaLibre Optimizer Lite v8 (Optimized)
// @namespace    pelotalibre.optimizer.min.v8
// @version      8.1.0
// @description  Versión liviana optimizada
// @match        https://pelotalibretv.com.co/*
// @grant        none
// @run-at       document-start
// ==/UserScript==

(function(){
'use strict';
const BLOCK=['ads','googletag','analytics','gtm','doubleclick','pixel','facebook.net','hotjar'];
function isBlocked(url){url=(url||'').toLowerCase();for(const p of BLOCK)if(url.includes(p))return true;return false;}
function blockNetwork(){
const originalFetch=window.fetch;
window.fetch=function(...args){const url=args[0]?.url||args[0];if(isBlocked(url))return new Promise(()=>{});return originalFetch.apply(this,args);};
const open=XMLHttpRequest.prototype.open;
XMLHttpRequest.prototype.open=function(m,url,...rest){if(isBlocked(url)){this.abort();return;}return open.call(this,m,url,...rest);};
}
function injectCSS(){
const style=document.createElement('style');
style.textContent=`header,footer,.hero,.popup,.modal,.toast,.banner,[role="dialog"],.language-selector,.btn-darkmode,.mobile-menu,.ads,[class*="ad-"],[id*="ad"],[class*="cookie"],[class*="newsletter"]{display:none!important;}`;
(document.head||document.documentElement).appendChild(style);
}
let done=false;
function hardClean(){
if(done)return;
done=true;
const main=document.querySelector("main");
if(!main)return;
const simple=main.querySelector("section.simple-page");
if(simple){
const container=simple.firstElementChild;
if(!container)return;
const children=Array.from(container.children);
for(const el of children){if(el.classList.contains("player"))continue;el.remove();}
return;
}
for(const el of main.children){
if(el.classList.contains("hero")||el.classList.contains("container"))el.remove();
}
}
function init(){blockNetwork();injectCSS();setTimeout(hardClean,2000);}
if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",init,{once:true});else init();
})();
